pub enum CommitmentValidationError { NoAsyncDetected, PrecompileMismatch { .. }, InputMismatch, OriginTxDecodeError(String), SignerRecoveryError(String), EvmError(String), TTLExceeded { ttl: u64, max: u64 }, InvalidPrecompileAddress(Address), ZeroExecutorAddress }

pub fn validate_commitment_structure(commitment: &TxAsyncCommitment) -> Result<(), CommitmentValidationError> {
    let max_ttl = max_ttl_blocks();
    if commitment.ttl == 0 || commitment.ttl > max_ttl { ... }
    if commitment.precompile_address != HTTP_CALL_PRECOMPILE && ... && commitment.precompile_address != PERSISTENT_AGENT_PRECOMPILE { ... }
    if commitment.executor_address.is_zero() { ... }
    Ok(())
}

pub fn validate_commitment_with_state<DB>(commitment: &TxAsyncCommitment, db: DB, env: EvmEnv, parent_header: &SealedHeader) -> Result<(), CommitmentValidationError> where DB: revm::Database, ... {
    let original_tx = commitment.decode_original_transaction()?;
    let (tx_signed, signer) = match original_tx { OriginalTransaction::AsyncSettlement(signed) => (signed.into(), ASYNC_SETTLEMENT_SYSTEM_SENDER), other => { ... tx_signed.recover_signer()? ... } };
    let recovered = Recovered::new_unchecked(tx_signed, signer);
    let mut inspector = AsyncPrecompileInspector::new();
    let ctx = Context::mainnet().with_db(db).with_cfg(env.cfg_env).with_block(env.block_env).build_mainnet_with_inspector(&mut inspector);
    let mut evm = EthEvm::new(ctx, true);
    let result = evm.transact(&recovered)?;
    let detected = inspector.async_call_result().ok_or(NoAsyncDetected)?;
    if detected.precompile_address != commitment.precompile_address { ... }
    if detected.input != commitment.precompile_input { ... }
    Ok(())
}

